mapper.select:
SELECT
    COALESCE(SUM(CASE WHEN amount < 0 THEN ABS(amount) ELSE 0 END), 0) AS total_expense,
    COALESCE(SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END), 0) AS total_income,
    COUNT(*)::int AS tx_count,
    COALESCE(AVG(ABS(amount)), 0) AS aov
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

SELECT
    t.category_id AS category_id,
    COALESCE(c.name, '미분류') AS category_name,
    SUM(ABS(t.amount)) AS total_amount
FROM projectdb.transactions t
LEFT JOIN projectdb.categories c ON t.category_id = c.category_id
WHERE t.user_id = #{userId}
  AND t.amount < 0
  AND t.tx_datetime >= #{startDate}
  AND t.tx_datetime < #{endDate}
GROUP BY t.category_id, c.name
ORDER BY total_amount DESC
LIMIT #{limit}

SELECT
    COALESCE(SUM(CASE WHEN amount < 0 THEN ABS(amount) ELSE 0 END), 0) AS total_expense,
    COALESCE(SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END), 0) AS total_income,
    COUNT(*)::int AS tx_count
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

SELECT
    COALESCE(NULLIF(TRIM(merchant), ''), '미입력') AS merchant,
    SUM(ABS(amount)) AS total_amount,
    COUNT(*)::int AS tx_count
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND amount < 0
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

  AND category_id = #{categoryId}

GROUP BY COALESCE(NULLIF(TRIM(merchant), ''), '미입력')
ORDER BY total_amount DESC
LIMIT #{limit}

SELECT CASE WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 21 AND 23 OR EXTRACT(HOUR FROM tx_datetime) BETWEEN 0 AND 2 THEN 'LATE_NIGHT' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 6 AND 10 THEN 'MORNING' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 11 AND 14 THEN 'LUNCH' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 17 AND 20 THEN 'DINNER' ELSE 'OTHER' END AS time_band, SUM(ABS(amount)) AS total_amount, COUNT(*)::int AS tx_count FROM projectdb.transactions WHERE user_id = #{userId} AND amount < 0 AND tx_datetime >= #{startDate} AND tx_datetime < #{endDate}
AND category_id = #{categoryId}
GROUP BY time_band ORDER BY total_amount DESC

SELECT
    EXTRACT(DOW FROM tx_datetime)::int AS dow,
    SUM(ABS(amount)) AS total_amount,
    COUNT(*)::int AS tx_count
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND amount < 0
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

  AND category_id = #{categoryId}

GROUP BY EXTRACT(DOW FROM tx_datetime)
ORDER BY dow

SELECT
    COUNT(*)::int AS tx_count,
    COALESCE(AVG(ABS(amount)), 0) AS aov,
    COALESCE(SUM(ABS(amount)), 0) AS total_amount
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND amount < 0
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

WITH cur AS ( SELECT CASE WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 21 AND 23 OR EXTRACT(HOUR FROM tx_datetime) BETWEEN 0 AND 2 THEN 'LATE_NIGHT' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 6 AND 10 THEN 'MORNING' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 11 AND 14 THEN 'LUNCH' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 17 AND 20 THEN 'DINNER' ELSE 'OTHER' END AS band, SUM(ABS(amount)) AS amt FROM projectdb.transactions WHERE user_id = #{userId} AND amount < 0 AND tx_datetime >= #{curStart} AND tx_datetime < #{curEnd}
AND category_id = #{categoryId}
GROUP BY band ), prev AS ( SELECT CASE WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 21 AND 23 OR EXTRACT(HOUR FROM tx_datetime) BETWEEN 0 AND 2 THEN 'LATE_NIGHT' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 6 AND 10 THEN 'MORNING' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 11 AND 14 THEN 'LUNCH' WHEN EXTRACT(HOUR FROM tx_datetime) BETWEEN 17 AND 20 THEN 'DINNER' ELSE 'OTHER' END AS band, SUM(ABS(amount)) AS amt FROM projectdb.transactions WHERE user_id = #{userId} AND amount < 0 AND tx_datetime >= #{prevStart} AND tx_datetime < #{prevEnd}
AND category_id = #{categoryId}
GROUP BY band ) SELECT COALESCE(cur.band, prev.band) AS time_band, COALESCE(cur.amt, 0) AS current_amount, COALESCE(prev.amt, 0) AS baseline_amount, (COALESCE(cur.amt, 0) - COALESCE(prev.amt, 0)) AS delta_amount FROM cur FULL OUTER JOIN prev ON cur.band = prev.band ORDER BY current_amount DESC

WITH cur AS ( SELECT EXTRACT(DOW FROM tx_datetime)::int AS dow, SUM(ABS(amount)) AS amt FROM projectdb.transactions WHERE user_id = #{userId} AND amount < 0 AND tx_datetime >= #{curStart} AND tx_datetime < #{curEnd}
AND category_id = #{categoryId}
GROUP BY EXTRACT(DOW FROM tx_datetime) ), prev AS ( SELECT EXTRACT(DOW FROM tx_datetime)::int AS dow, SUM(ABS(amount)) AS amt FROM projectdb.transactions WHERE user_id = #{userId} AND amount < 0 AND tx_datetime >= #{prevStart} AND tx_datetime < #{prevEnd}
AND category_id = #{categoryId}
GROUP BY EXTRACT(DOW FROM tx_datetime) ) SELECT COALESCE(cur.dow, prev.dow)::int AS dow, COALESCE(cur.amt, 0) AS current_amount, COALESCE(prev.amt, 0) AS baseline_amount, (COALESCE(cur.amt, 0) - COALESCE(prev.amt, 0)) AS delta_amount FROM cur FULL OUTER JOIN prev ON cur.dow = prev.dow ORDER BY dow

SELECT
    COALESCE(NULLIF(TRIM(merchant), ''), '미입력') AS merchant,
    SUM(ABS(amount)) AS total_amount,
    COUNT(*)::int AS tx_count
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND amount < 0
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

  AND category_id = #{categoryId}

GROUP BY COALESCE(NULLIF(TRIM(merchant), ''), '미입력')
ORDER BY total_amount DESC
LIMIT #{limit}

SELECT
    #{keyword} AS keyword,
    COALESCE(SUM(ABS(amount)), 0) AS total_amount,
    COUNT(*)::int AS tx_count
FROM projectdb.transactions
WHERE user_id = #{userId}
  AND amount < 0
  AND tx_datetime >= #{startDate}
  AND tx_datetime < #{endDate}

  AND category_id = #{categoryId}

  AND ( merchant ILIKE '%' || #{keyword} || '%' OR memo ILIKE '%' || #{keyword} || '%' )
